#!/usr/bin/env node
/**
 * Generates the JP expansion question banks:
 *   - jp_car_expansion.json  (210 questions, ids jp_car_0141..0350)
 *   - jp_moto_expansion.json (150 questions, ids jp_moto_0101..0250)
 *
 * Run: node scripts/generate-jp-expansion.mjs
 * Then merge into the main banks with: node scripts/merge-jp-expansion.mjs
 */
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const outDir = path.join(__dirname, '..', 'content', 'questions');

const TF_CHOICES = [
  { text: { ja: '正しい', my: 'မှန်သည်' } },
  { text: { ja: '誤り', my: 'မှားသည်' } },
];

function media(src, ja, my) {
  return {
    type: 'image',
    src: `/signs/jp/${src}`,
    alt: { ja, my: my.slice(0, 60) },
  };
}

/** tuple: [ja, my, answer(0|1), explJa, explMy, mediaSrc, difficulty] */
function tf([ja, my, answer, ejJa, ejMy, m, difficulty]) {
  return {
    difficulty,
    prompt: { ja, my },
    choices: TF_CHOICES,
    answer,
    explanation: { ja: ejJa, my: ejMy },
    media: media(m, ja, my),
  };
}

/**
 * hazard entry shape:
 * { ja, my, ejJa, ejMy, m, difficulty,
 *   parts: [[label, partJa, partMy, answer], ...] }
 */
function hazard({ ja, my, ejJa, ejMy, m, difficulty, parts }) {
  return {
    difficulty,
    prompt: { ja, my },
    choices: TF_CHOICES,
    answer: 0,
    explanation: { ja: ejJa, my: ejMy },
    media: media(m, ja, my),
    points: 2,
    parts: parts.map(([label, pja, pmy, ans]) => ({
      label,
      prompt: { ja: pja, my: pmy },
      answer: ans,
    })),
  };
}

function build(category, startNum, sections) {
  const out = [];
  let n = startNum;
  for (const [topic, items, kind] of sections) {
    for (const item of items) {
      const q = kind === 'hazard' ? hazard(item) : tf(item);
      q.id = `${category}_${String(n).padStart(4, '0')}`;
      q.category = category;
      q.topic = topic;
      out.push(q);
      n++;
    }
  }
  return out;
}

